const eventMap = {
  'job.closed': 'posting_closed',
  'job.updated': 'jd_changed',
  'job.reopened': 'posting_reopened',
  'job.salary_added': 'salary_added'
};
const body = $input.first().json.body ?? $input.first().json;
const notificationType = eventMap[body.event] ?? 'jd_changed';
const messageMap = {
  posting_closed: `The job posting for ${body.job_title ?? 'your application'} at ${body.company ?? 'the company'} has closed.`,
  jd_changed: `The job description for ${body.job_title ?? 'your application'} at ${body.company ?? 'the company'} was updated.`,
  posting_reopened: `${body.job_title ?? 'A tracked posting'} at ${body.company ?? 'the company'} is hiring again.`,
  salary_added: `Salary information was added to ${body.job_title ?? 'your application'} at ${body.company ?? 'the company'}.`
};
return [{
  json: {
    jobId: body.internal_job_id ?? body.job_id,
    userId: body.subscriber_metadata?.user_id ?? body.subscriber_metadata?.userId ?? '',
    notificationType,
    message: messageMap[notificationType]
  }
}];
